# Register the minio-repo snapshot repository
kubectl exec -n elasticsearch curl-test -- curl -s -X PUT \
  "http://10.96.244.131:9200/_snapshot/minio-repo" \
  -H 'Content-Type: application/json' \
  -d '{
    "type": "s3",
    "settings": {
      "bucket": "es-backups",
      "endpoint": "minio.elasticsearch.svc.cluster.local:9000",
      "protocol": "http",
      "path_style_access": true
    }
  }' 2>&1

